        tools: [{
          type: 'function',
          function: {
            name: 'soul_mt5_analyze',
            description: 'Analyze trading symbol with technical indicators',
            parameters: { type: 'object', properties: { symbol: { type: 'string', description: 'Trading symbol e.g. XAUUSD' } }, required: ['symbol'] }
          }
        }],
        temperature: 0.3,
        max_tokens: 500
      }\)
    }\);
    const data = await res.json\(\);
    const ms = Date.now\(\) - start;
    const msg = data.choices?.[0]?.message;
    const calledTool = msg?.tool_calls?.length > 0;
    const toolName = calledTool ? msg.tool_calls[0].function.name : null;
    const textOnly = !calledTool && msg?.content?.length > 0;
