const Database = require\('better-sqlite3'\);
const path = require\('path'\);
const os = require\('os'\);
const dbPath = path.join\(os.homedir\(\), '.soul', 'soul.db'\);
const db = new Database\(dbPath\);
const groqRow = db.prepare\(\\"SELECT api_key FROM soul_llm_config WHERE provider_id = 'groq'\\"\).get\(\);
db.close\(\);

// Test all free Groq models for tool calling
const models = [
  'qwen/qwen3-32b',
  'llama-3.3-70b-versatile',
  'moonshotai/kimi-k2-instruct',
  'meta-llama/llama-4-scout-17b-16e-instruct',
  'llama-3.1-8b-instant',
];

async function test\(model\) {
  const start = Date.now\(\);
  try {
    const res = await globalThis.fetch\('https://api.groq.com/openai/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + groqRow.api_key },
      body: JSON.stringify\({
        model,
        messages: [
          { role: 'system', content: 'You are Soul, an AI companion. When the user asks you to do something, ALWAYS use the appropriate tool. Reply in Thai.' },
          { role: 'user', content: 'จำไว้ว่าวันนี้ฉันมีประชุมตอนบ่าย 2' }
        ],
        tools: [
          { type: 'function', function: { name: 'soul_remember', description: 'Store something in memory for later recall', parameters: { type: 'object', properties: { content: { type: 'string', description: 'What to remember' }, category: { type: 'string' } }, required: ['content'] } } },
          { type: 'function', function: { name: 'soul_mt5_analyze', description: 'Analyze trading symbol', parameters: { type: 'object', properties: { symbol: { type: 'string' } }, required: ['symbol'] } } },
          { type: 'function', function: { name: 'soul_web_search', description: 'Search the web', parameters: { type: 'object', properties: { query: { type: 'string' } }, required: ['query'] } } },
        ],
        temperature: 0.3,
        max_tokens: 300
      }\)
    }\);
    const data = await res.json\(\);
    const ms = Date.now\(\) - start;
    const msg = data.choices && data.choices[0] && data.choices[0].message;
    if \(!msg\) { console.log\(model + ': no response'\); return; }
    const calledTool = msg.tool_calls && msg.tool_calls.length > 0;
    if \(calledTool\) {
      const tc = msg.tool_calls[0];
      console.log\(model + ' \(' + ms + 'ms\) OK → ' + tc.function.name + '\(' + tc.function.arguments.substring\(0,80\) + '\)'\);
    } else {
      const text = \(msg.content || ''\).replace\(/<think>[\\\\s\\\\S]*?<\\\\/think>/g, ''\).trim\(\);
      console.log\(model + ' \(' + ms + 'ms\) FAIL → text: ' + text.substring\(0,80\)\);
    }
  } catch\(e\) {
    console.log\(model + ': ERROR ' + e.message\);
  }
}

\(async \(\) => {
  // Run sequentially to avoid rate limit
  for \(const m of models\) {
    await test\(m\);
  }
}\)\(\);
